import { usePlayerStore } from '../store/playerStore';
import { useSettingsStore } from '../store/settingsStore';

let initialized = false;
let keydownHandler: ((e: KeyboardEvent) => void) | null = null;

function formatCombo(e: KeyboardEvent): string {
  const parts: string[] = [];
  if (e.ctrlKey) parts.push('Ctrl');
  if (e.altKey) parts.push('Alt');
  if (e.shiftKey) parts.push('Shift');
  const key = e.key.length === 1 ? e.key.toUpperCase() : e.key;
  parts.push(key);
  return parts.join('+');
}

/**
 * 初始化媒体快捷键: 系统媒体键 (Media Session API) + 页面内自定义快捷键
 */
export function initMediaKeys() {
  if (initialized) return;
  initialized = true;

  // 系统媒体键 / 通知中心控制
  if ('mediaSession' in navigator) {
    const ms = navigator.mediaSession;
    ms.setActionHandler('play', () => usePlayerStore.getState().togglePlay());
    ms.setActionHandler('pause', () => usePlayerStore.getState().togglePlay());
    ms.setActionHandler('previoustrack', () => usePlayerStore.getState().prev());
    ms.setActionHandler('nexttrack', () => usePlayerStore.getState().next());
  }

  keydownHandler = (e: KeyboardEvent) => {
    const { settings } = useSettingsStore.getState();
    if (!settings.mediaKeysEnabled) return;

    const target = e.target as HTMLElement;
    if (target && ['INPUT', 'TEXTAREA'].includes(target.tagName)) return;

    const combo = formatCombo(e);
    const { shortcuts } = settings;
    const player = usePlayerStore.getState();

    if (combo === shortcuts.playPause) {
      e.preventDefault();
      player.togglePlay();
    } else if (combo === shortcuts.next) {
      e.preventDefault();
      player.next();
    } else if (combo === shortcuts.prev) {
      e.preventDefault();
      player.prev();
    } else if (combo === shortcuts.volumeUp) {
      e.preventDefault();
      player.setVolume(Math.min(1, player.volume + 0.1));
    } else if (combo === shortcuts.volumeDown) {
      e.preventDefault();
      player.setVolume(Math.max(0, player.volume - 0.1));
    }
  };

  window.addEventListener('keydown', keydownHandler);
}

/**
 * 更新媒体会话元数据 (在通知中心 / 锁屏展示当前播放歌曲信息)
 */
export function updateMediaSessionMeta(meta: {
  title: string;
  artist: string;
  album?: string;
  artwork?: string;
}) {
  if (!('mediaSession' in navigator) || !window.MediaMetadata) return;
  navigator.mediaSession.metadata = new window.MediaMetadata({
    title: meta.title,
    artist: meta.artist,
    album: meta.album || '',
    artwork: meta.artwork ? [{ src: meta.artwork, sizes: '300x300', type: 'image/jpeg' }] : [],
  });
}
